// Generated by AI (UnitTest MCP)
//! Persistence for design items (ADR-0023): register, read, and the guarded
//! accept/reject state transition. Like the claim CAS, the decision is a single
//! guarded statement so concurrent deciders cannot both win.

use rusqlite::{params, Row};

use crate::design::{
    design_id_from_path, DesignItem, DesignMetadata, DesignPromotion, DesignPromotionStatus,
    DesignStatus,
};
use crate::error::{LodestarError, Result};
use crate::model::{Goal, GoalKind, Task};

use super::{collect, LodestarStore};

const DESIGN_COLS: &str =
    "id, adr_path, title, summary, status, proposed_by, decided_by, reason, created_at, updated_at, promotion_status, spawned_goal_id";

impl LodestarStore {
    /// Reconcile structured repository ADR metadata into the durable design
    /// ledger. Existing rows always win: repository discovery must never
    /// overwrite a Design Board decision or re-arm promotion.
    pub fn reconcile_design_item(&self, metadata: &DesignMetadata, now: i64) -> Result<DesignItem> {
        let id = design_id_from_path(&metadata.adr_path);
        self.conn.execute(
            "INSERT OR IGNORE INTO design_items
                (id, adr_path, title, summary, status, proposed_by, decided_by,
                 reason, created_at, updated_at, promotion_status, spawned_goal_id)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, NULL, NULL, ?7, ?7,
                     'not_required', NULL)",
            params![
                id,
                metadata.adr_path,
                metadata.title,
                metadata.summary,
                metadata.status.as_str(),
                metadata.proposed_by,
                now
            ],
        )?;
        self.get_design_item(&id)?
            .ok_or_else(|| LodestarError::NotFound(id))
    }

    /// Register a new proposed design item. Fails if the ADR is already
    /// registered (its id is derived from the ADR path, so this is idempotent
    /// per ADR).
    pub fn register_design_item(
        &self,
        id: &str,
        adr_path: &str,
        title: &str,
        summary: &str,
        proposed_by: Option<&str>,
        now: i64,
    ) -> Result<DesignItem> {
        if self.get_design_item(id)?.is_some() {
            return Err(LodestarError::Invalid(format!(
                "design item already registered: {id}"
            )));
        }
        self.conn.execute(
            "INSERT INTO design_items
                (id, adr_path, title, summary, status, proposed_by, decided_by, reason, created_at, updated_at)
             VALUES (?1, ?2, ?3, ?4, 'proposed', ?5, NULL, NULL, ?6, ?6)",
            params![id, adr_path, title, summary, proposed_by, now],
        )?;
        self.get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))
    }

    pub fn get_design_item(&self, id: &str) -> Result<Option<DesignItem>> {
        let sql = format!("SELECT {DESIGN_COLS} FROM design_items WHERE id = ?1");
        let mut stmt = self.conn.prepare(&sql)?;
        let mut rows = stmt.query(params![id])?;
        match rows.next()? {
            Some(row) => Ok(Some(row_to_design(row)?)),
            None => Ok(None),
        }
    }

    /// List design items, oldest first. `status = None` returns every item
    /// (durable audit view); `Some(Proposed)` is the Design Board.
    pub fn list_design_items(&self, status: Option<DesignStatus>) -> Result<Vec<DesignItem>> {
        match status {
            Some(status) => {
                let sql = format!(
                    "SELECT {DESIGN_COLS} FROM design_items WHERE status = ?1 \
                     ORDER BY created_at ASC, id ASC"
                );
                let mut stmt = self.conn.prepare(&sql)?;
                let rows = stmt.query_map(params![status.as_str()], row_to_design)?;
                collect(rows)
            }
            None => {
                let sql = format!(
                    "SELECT {DESIGN_COLS} FROM design_items ORDER BY created_at ASC, id ASC"
                );
                let mut stmt = self.conn.prepare(&sql)?;
                let rows = stmt.query_map([], row_to_design)?;
                collect(rows)
            }
        }
    }

    /// Human-actionable Design Board rows: proposed decisions plus accepted
    /// designs whose implementation promotion is pending or retryable.
    pub fn actionable_design_items(&self) -> Result<Vec<DesignItem>> {
        let sql = format!(
            "SELECT {DESIGN_COLS} FROM design_items
             WHERE status = 'proposed'
                OR (status = 'accepted' AND promotion_status = 'pending')
             ORDER BY created_at ASC, id ASC"
        );
        let mut stmt = self.conn.prepare(&sql)?;
        let rows = stmt.query_map([], row_to_design)?;
        collect(rows)
    }

    /// Resolve the durable objective/task/constraint provenance for a
    /// materialized design. Proposed and pending designs have no materialized
    /// plan yet and return `None`; this read never invokes planning.
    pub fn design_promotion(&self, id: &str) -> Result<Option<DesignPromotion>> {
        let item = self
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
        if item.promotion_status != DesignPromotionStatus::Materialized {
            return Ok(None);
        }
        self.resolve_promotion(&item).map(Some)
    }

    /// Guarded CAS: move a *proposed* item to accepted/rejected. Returns `false`
    /// when the item is not currently proposed (missing or already decided), so
    /// a concurrent second decider cannot overwrite the first.
    pub fn decide_design_item(
        &self,
        id: &str,
        target: DesignStatus,
        decided_by: &str,
        reason: Option<&str>,
        now: i64,
    ) -> Result<bool> {
        // Accepting arms promotion (pending); any other decision leaves it off.
        let promotion = if target == DesignStatus::Accepted {
            DesignPromotionStatus::Pending
        } else {
            DesignPromotionStatus::NotRequired
        };
        let changed = self.conn.execute(
            "UPDATE design_items SET status = ?2, decided_by = ?3, reason = ?4, promotion_status = ?5, updated_at = ?6
             WHERE id = ?1 AND status = 'proposed'",
            params![id, target.as_str(), decided_by, reason, promotion.as_str(), now],
        )?;
        Ok(changed == 1)
    }

    /// Idempotent promotion of an accepted design into implementation work
    /// (ADR-0023). Materialises exactly once via a guarded CAS on
    /// `promotion_status`; a retry after materialisation returns the already
    /// linked plan rather than creating duplicates. A failed decomposition
    /// leaves promotion `pending` and never rolls back the human acceptance.
    pub fn promote_design_item(
        &self,
        id: &str,
        objective_goal_id: &str,
        drafts: &[(String, String)],
        constraints: &[(GoalKind, String, String)],
        now: i64,
    ) -> Result<DesignPromotion> {
        let item = self
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
        if item.status != DesignStatus::Accepted {
            return Err(LodestarError::Invalid(format!(
                "design item {id} is {}; only an accepted design can be promoted",
                item.status.as_str()
            )));
        }
        // Already materialised: return the linked plan (idempotent retry).
        if item.promotion_status == DesignPromotionStatus::Materialized {
            return self.resolve_promotion(&item);
        }
        let goal = self
            .get_goal(objective_goal_id)?
            .ok_or_else(|| LodestarError::NotFound(objective_goal_id.to_string()))?;
        if goal.kind != GoalKind::Objective {
            return Err(LodestarError::Invalid(format!(
                "promotion target {objective_goal_id} is a {}; tasks must serve an objective",
                goal.kind.as_str()
            )));
        }
        // Guarded CAS: claim materialisation exactly once.
        let won = self.conn.execute(
            "UPDATE design_items SET promotion_status = 'materialized', spawned_goal_id = ?2, updated_at = ?3
             WHERE id = ?1 AND status = 'accepted' AND promotion_status = 'pending'",
            params![id, objective_goal_id, now],
        )?;
        if won != 1 {
            // A concurrent caller materialised first; return the linked plan.
            let item = self
                .get_design_item(id)?
                .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
            return self.resolve_promotion(&item);
        }
        // Record objective provenance, then the tasks under it.
        self.link_design_goal(id, &goal.id, "objective", 0)?;
        let mut tasks = Vec::with_capacity(drafts.len());
        for (position, (title, acceptance)) in drafts.iter().enumerate() {
            let task = self.create_task(&goal.id, title, acceptance, None, now)?;
            self.link_design_task(id, &task.id, position as i64)?;
            tasks.push(task);
        }
        // Register the mandated constraints into the constitution and link them.
        let mut registered = Vec::with_capacity(constraints.len());
        for (position, (kind, title, statement)) in constraints.iter().enumerate() {
            let constraint = self.define_goal(*kind, title, statement, None, now)?;
            self.link_design_goal(id, &constraint.id, kind.as_str(), (position as i64) + 1)?;
            registered.push(constraint);
        }
        let item = self
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
        Ok(DesignPromotion {
            item,
            goal,
            tasks,
            constraints: registered,
        })
    }

    /// Reconstruct a materialised promotion from its durable provenance links so
    /// a retry returns the same plan without re-running planning.
    fn resolve_promotion(&self, item: &DesignItem) -> Result<DesignPromotion> {
        let goal_id = item.spawned_goal_id.clone().ok_or_else(|| {
            LodestarError::Invalid(format!(
                "design item {} is materialised but has no objective goal",
                item.id
            ))
        })?;
        let goal = self
            .get_goal(&goal_id)?
            .ok_or_else(|| LodestarError::NotFound(goal_id.clone()))?;
        let tasks = self.linked_tasks(&item.id)?;
        let constraints = self.linked_constraint_goals(&item.id)?;
        Ok(DesignPromotion {
            item: item.clone(),
            goal,
            tasks,
            constraints,
        })
    }

    fn link_design_goal(
        &self,
        design_id: &str,
        goal_id: &str,
        role: &str,
        position: i64,
    ) -> Result<()> {
        self.conn.execute(
            "INSERT OR IGNORE INTO design_goal_links (design_id, goal_id, role, position)
             VALUES (?1, ?2, ?3, ?4)",
            params![design_id, goal_id, role, position],
        )?;
        Ok(())
    }

    fn link_design_task(&self, design_id: &str, task_id: &str, position: i64) -> Result<()> {
        self.conn.execute(
            "INSERT OR IGNORE INTO design_task_links (design_id, task_id, position)
             VALUES (?1, ?2, ?3)",
            params![design_id, task_id, position],
        )?;
        Ok(())
    }

    fn linked_tasks(&self, design_id: &str) -> Result<Vec<Task>> {
        let ids: Vec<String> = {
            let mut stmt = self.conn.prepare(
                "SELECT task_id FROM design_task_links WHERE design_id = ?1 ORDER BY position ASC",
            )?;
            let rows = stmt.query_map(params![design_id], |row| row.get::<_, String>(0))?;
            collect(rows)?
        };
        let mut tasks = Vec::with_capacity(ids.len());
        for id in ids {
            if let Some(task) = self.get_task(&id)? {
                tasks.push(task);
            }
        }
        Ok(tasks)
    }

    fn linked_constraint_goals(&self, design_id: &str) -> Result<Vec<Goal>> {
        let ids: Vec<String> = {
            let mut stmt = self.conn.prepare(
                "SELECT goal_id FROM design_goal_links
                 WHERE design_id = ?1 AND role <> 'objective' ORDER BY position ASC",
            )?;
            let rows = stmt.query_map(params![design_id], |row| row.get::<_, String>(0))?;
            collect(rows)?
        };
        let mut goals = Vec::with_capacity(ids.len());
        for id in ids {
            if let Some(goal) = self.get_goal(&id)? {
                goals.push(goal);
            }
        }
        Ok(goals)
    }
}

fn row_to_design(row: &Row) -> rusqlite::Result<DesignItem> {
    Ok(DesignItem {
        id: row.get(0)?,
        adr_path: row.get(1)?,
        title: row.get(2)?,
        summary: row.get(3)?,
        status: DesignStatus::from_tag(&row.get::<_, String>(4)?).unwrap_or(DesignStatus::Proposed),
        proposed_by: row.get(5)?,
        decided_by: row.get(6)?,
        reason: row.get(7)?,
        created_at: row.get(8)?,
        updated_at: row.get(9)?,
        promotion_status: DesignPromotionStatus::from_tag(&row.get::<_, String>(10)?)
            .unwrap_or(DesignPromotionStatus::NotRequired),
        spawned_goal_id: row.get(11)?,
    })
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::store::test_support::{goal, store, NOW};

    #[test]
    fn reconciliation_is_idempotent_and_never_creates_tasks() {
        let store = store();
        let metadata = DesignMetadata {
            adr_path: "docs/adr/0026-constitution.md".into(),
            title: "Constitution".into(),
            summary: "review governance".into(),
            status: DesignStatus::Proposed,
            proposed_by: Some("workspace-sensor".into()),
        };
        let first = store.reconcile_design_item(&metadata, NOW).unwrap();
        let retry = store
            .reconcile_design_item(
                &DesignMetadata {
                    title: "Changed metadata must not overwrite review state".into(),
                    summary: "changed".into(),
                    status: DesignStatus::Rejected,
                    proposed_by: Some("different-sensor".into()),
                    ..metadata
                },
                NOW + 1,
            )
            .unwrap();

        assert_eq!(retry, first);
        assert_eq!(store.list_design_items(None).unwrap(), vec![first]);
        assert!(store.next_task(NOW + 1).unwrap().is_none());
    }

    #[test]
    fn historical_terminal_adrs_import_without_arming_promotion() {
        let store = store();
        for (id, status) in [
            ("design:0001-accepted", DesignStatus::Accepted),
            ("design:0002-rejected", DesignStatus::Rejected),
        ] {
            let item = store
                .reconcile_design_item(
                    &DesignMetadata {
                        adr_path: format!("docs/adr/{}.md", &id[7..]),
                        title: id.into(),
                        summary: "historical".into(),
                        status,
                        proposed_by: None,
                    },
                    NOW,
                )
                .unwrap();
            assert_eq!(item.status, status);
            assert_eq!(item.promotion_status, DesignPromotionStatus::NotRequired);
        }

        assert!(store.actionable_design_items().unwrap().is_empty());
        assert!(store.next_task(NOW).unwrap().is_none());
    }

    #[test]
    fn actionable_board_preserves_decisions_and_tracks_pending_only() {
        let store = store();
        let proposed = store
            .reconcile_design_item(
                &DesignMetadata {
                    adr_path: "docs/adr/0030-proposed.md".into(),
                    title: "Proposed".into(),
                    summary: "review me".into(),
                    status: DesignStatus::Proposed,
                    proposed_by: Some("planner".into()),
                },
                NOW,
            )
            .unwrap();
        let pending = store
            .register_design_item(
                "design:0031-pending",
                "docs/adr/0031-pending.md",
                "Pending",
                "promote me",
                Some("planner"),
                NOW + 1,
            )
            .unwrap();
        assert!(store
            .decide_design_item(
                &pending.id,
                DesignStatus::Accepted,
                "reviewer",
                None,
                NOW + 2,
            )
            .unwrap());

        let before = store.get_design_item(&pending.id).unwrap().unwrap();
        let reconciled = store
            .reconcile_design_item(
                &DesignMetadata {
                    adr_path: pending.adr_path.clone(),
                    title: "Repository status must not overwrite the decision".into(),
                    summary: "changed".into(),
                    status: DesignStatus::Rejected,
                    proposed_by: None,
                },
                NOW + 3,
            )
            .unwrap();
        assert_eq!(reconciled, before);

        let rows = store.actionable_design_items().unwrap();
        assert_eq!(
            rows.iter().map(|item| item.id.as_str()).collect::<Vec<_>>(),
            vec![proposed.id.as_str(), pending.id.as_str(),]
        );

        let objective = goal(&store);
        store
            .promote_design_item(
                &pending.id,
                &objective.id,
                &[("Implement pending".into(), "done".into())],
                &[],
                NOW + 4,
            )
            .unwrap();
        assert_eq!(
            store
                .actionable_design_items()
                .unwrap()
                .iter()
                .map(|item| item.id.as_str())
                .collect::<Vec<_>>(),
            vec![proposed.id.as_str()]
        );
    }

    #[test]
    fn design_promotion_is_read_only_and_resolves_materialized_provenance() {
        let store = store();
        let item = store
            .register_design_item(
                "design:0040-materialized",
                "docs/adr/0040-materialized.md",
                "Materialized",
                "ship it",
                Some("planner"),
                NOW,
            )
            .unwrap();
        assert!(store.design_promotion(&item.id).unwrap().is_none());
        assert!(store
            .decide_design_item(&item.id, DesignStatus::Accepted, "reviewer", None, NOW + 1,)
            .unwrap());
        assert!(store.design_promotion(&item.id).unwrap().is_none());

        let objective = goal(&store);
        let created = store
            .promote_design_item(
                &item.id,
                &objective.id,
                &[("Implement materialized".into(), "done".into())],
                &[(
                    GoalKind::Constraint,
                    "Keep it deterministic".into(),
                    "no model on reconciliation".into(),
                )],
                NOW + 2,
            )
            .unwrap();
        let resolved = store.design_promotion(&item.id).unwrap().unwrap();

        assert_eq!(resolved.item, created.item);
        assert_eq!(resolved.goal.id, created.goal.id);
        assert_eq!(
            resolved
                .tasks
                .iter()
                .map(|task| &task.id)
                .collect::<Vec<_>>(),
            created
                .tasks
                .iter()
                .map(|task| &task.id)
                .collect::<Vec<_>>()
        );
        assert_eq!(
            resolved
                .constraints
                .iter()
                .map(|goal| &goal.id)
                .collect::<Vec<_>>(),
            created
                .constraints
                .iter()
                .map(|goal| &goal.id)
                .collect::<Vec<_>>()
        );
        assert_eq!(store.list_design_items(None).unwrap().len(), 1);
    }
}
